import styles from "./Dialogs.module.css";

const Dialogs = (props) => {
  return (
    <div>
      <div className={styles.dialogs}>
        <div className={styles.dialogItems}>
          <div className={styles.dialogItem}>Ilya</div>
          <div className={styles.dialogItem}>Alexey</div>
          <div className={styles.dialogItem}>Sergey</div>
          <div className={styles.dialogItem}>Artem</div>
          <div className={styles.dialogItem}>Dmitriy</div>
          <div className={styles.dialogItem}>Vladimir</div>
        </div>
        <div className={styles.dialogMessages}>
          <div className={styles.dialogMessage}>Hi</div>
          <div className={styles.dialogMessage}>How are you</div>
          <div className={styles.dialogMessage}>Nice to meet you</div>
        </div>
      </div>
    </div>
  );
};

export default Dialogs;
